import{_ as e,o as a,c as t,O as o}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Custom Pages","description":"","frontmatter":{},"headers":[],"relativePath":"administration/content/pages.md","filePath":"administration/content/pages.md","lastUpdated":1773166967000}'),n={name:"administration/content/pages.md"},i=o('<h1 id="custom-pages" tabindex="-1">Custom Pages <a class="header-anchor" href="#custom-pages" aria-label="Permalink to &quot;Custom Pages&quot;">​</a></h1><p>Custom pages let you create standalone content on your board, such as rules, guidelines, about pages or any other static information. You can find them under the <strong>Content</strong> navigation group in the Admin CP.</p><nav class="table-of-contents"><ul><li><a href="#creating-a-page">Creating a page</a></li><li><a href="#content-formats">Content formats</a><ul><li><a href="#bbcode">BBCode</a></li><li><a href="#html">HTML</a></li></ul></li><li><a href="#publishing">Publishing</a></li><li><a href="#adding-pages-to-the-board-menu">Adding pages to the board menu</a></li><li><a href="#editing-and-deleting-pages">Editing and deleting pages</a></li></ul></nav><h2 id="creating-a-page" tabindex="-1">Creating a page <a class="header-anchor" href="#creating-a-page" aria-label="Permalink to &quot;Creating a page&quot;">​</a></h2><p>Click <strong>Create Page</strong> to add a new page. Each page has the following fields:</p><ul><li><strong>Title</strong> — the page heading displayed to users and in the browser tab.</li><li><strong>Slug</strong> — the URL-friendly identifier for the page (letters, numbers, dashes and underscores only). Must be unique across your board.</li><li><strong>Description</strong> — an optional short summary, used as a meta description for search engines.</li><li><strong>Content</strong> — the body of the page. Supports up to 60,000 characters.</li><li><strong>Content Format</strong> — choose between <strong>BBCode</strong> or <strong>HTML</strong>.</li><li><strong>Sort Order</strong> — controls the display order when listing pages.</li></ul><img width="1936" height="1059" alt="image" src="https://github.com/user-attachments/assets/a0b99970-ef3c-4e22-a3b8-cf7b7a18c430"><h2 id="content-formats" tabindex="-1">Content formats <a class="header-anchor" href="#content-formats" aria-label="Permalink to &quot;Content formats&quot;">​</a></h2><h3 id="bbcode" tabindex="-1">BBCode <a class="header-anchor" href="#bbcode" aria-label="Permalink to &quot;BBCode&quot;">​</a></h3><p>The default format. Write your page content using BBCode tags, which are automatically converted to HTML when displayed. This is the same syntax used throughout the board for posts and signatures.</p><h3 id="html" tabindex="-1">HTML <a class="header-anchor" href="#html" aria-label="Permalink to &quot;HTML&quot;">​</a></h3><p>For advanced layouts, choose the HTML format. This allows you to write raw HTML, including <code>&lt;style&gt;</code> and <code>&lt;script&gt;</code> tags for fully custom page designs.</p><blockquote><p>Note: HTML pages give you full control over the markup. Be careful when pasting HTML from external sources.</p></blockquote><h2 id="publishing" tabindex="-1">Publishing <a class="header-anchor" href="#publishing" aria-label="Permalink to &quot;Publishing&quot;">​</a></h2><p>Pages are not visible to users until published. Toggle the <strong>Published</strong> checkbox when creating or editing a page to control its visibility. Only published pages are accessible on the front end.</p><h2 id="adding-pages-to-the-board-menu" tabindex="-1">Adding pages to the board menu <a class="header-anchor" href="#adding-pages-to-the-board-menu" aria-label="Permalink to &quot;Adding pages to the board menu&quot;">​</a></h2><p>Enable the <strong>Show in Menu</strong> option to automatically add the page as a menu item. When this option is toggled:</p><ul><li>A menu item linking to the page is created automatically.</li><li>If you later disable this option, the corresponding menu item is removed.</li></ul><p>You can also manage menu items separately from the <a href="/administration/content/board-menu.html">Board Menu</a> section.</p><h2 id="editing-and-deleting-pages" tabindex="-1">Editing and deleting pages <a class="header-anchor" href="#editing-and-deleting-pages" aria-label="Permalink to &quot;Editing and deleting pages&quot;">​</a></h2><p>To edit a page, click on it from the pages list. All fields can be updated at any time. If the page has a linked menu item and you delete the page, the menu item is also removed automatically.</p>',21),s=[i];function r(l,d,g,h,u,c){return a(),t("div",null,s)}const b=e(n,[["render",r]]);export{m as __pageData,b as default};
